<?php
namespace App\Models;
use Illuminate\Database\Eloquent\Factories\HasFactory; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\HasMany;
class Invoice extends Model { use HasFactory; protected $fillable=['business_id','customer_id','invoice_number','issue_date','due_date','status','subtotal','tax_total','total','amount_paid','notes']; protected function casts(): array { return ['issue_date'=>'date','due_date'=>'date','subtotal'=>'decimal:2','tax_total'=>'decimal:2','total'=>'decimal:2','amount_paid'=>'decimal:2']; } public function business(): BelongsTo { return $this->belongsTo(Business::class); } public function customer(): BelongsTo { return $this->belongsTo(Customer::class); } public function items(): HasMany { return $this->hasMany(InvoiceItem::class); } public function payments(): HasMany { return $this->hasMany(Payment::class); } public function getBalanceAttribute(): string { return number_format((float)$this->total - (float)$this->amount_paid, 2, '.', ''); } }
